trigger.custom:
function(...)
    local voit = C_Spell.GetSpellCooldown(263165);
    local gcd = 1.5 / (UnitSpellHaste("player") * 0.01 + 1)

    if (voit and aura_env.config["mindFlayGCDs"]) then
        local voitCdLeft = voit.startTime + voit.duration - GetTime();
        if (voitCdLeft > 0) then
            if (voitCdLeft <= (gcd * aura_env.config["mindFlayGCDs"])) then
                return true
            end
        end
    end
    return false;
end

triggers.customTriggerLogic:
function(t)
    return t[2] and (
        (t[1] and not t[3]) or -- Mind Flay pooling
        t[3] -- Less than or equal to 4 seconds
    )
end

check.value:
function()
    local value = aura_env.states[1].tooltip1;
    if value then
        local max_hp = UnitHealthMax("player");
        local ten = max_hp * .1;
        if value >= ten then
            return true
        else
            return false
        end
    end
end

trigger.custom:
function(event,insanity,max)
    aura_env.insanity = insanity;
    aura_env.max = max;
    return true
end

function(event, ...)
    local unit, _, _ = ...;
    local currentInsanity = UnitPower("player", 13);
    local maxInsanity = UnitPowerMax("player", 13);
    if unit == "player" then
        local insanityGain = 0;
        local _,_,_,_,_,_,_,_,currentSpell = UnitCastingInfo('player');

        if currentSpell == nil then
            WeakAuras.ScanEvents("INSANITY_BAR_INCOMING",0,0);

            aura_env.ib_gain = currentInsanity;
            aura_env.ib_max = maxInsanity;
            return true;
        end

        local insanitySpellAmount = aura_env.insanitySpells[currentSpell];
        if insanitySpellAmount ~= nil then
            insanityGain = insanitySpellAmount;
        else
            WeakAuras.ScanEvents("INSANITY_BAR_INCOMING",0,0);

            aura_env.ib_gain = currentInsanity;
            aura_env.ib_max = maxInsanity;
            return true;
        end

        local totalInsanityGain = currentInsanity+insanityGain;

        WeakAuras.ScanEvents("INSANITY_BAR_INCOMING",math.floor(totalInsanityGain),maxInsanity);
        aura_env.ib_gain = totalInsanityGain;
        aura_env.ib_max = maxInsanity;
        return true;
    else 
        return true;
    end
end

